(3, 'hesitate', 'hesitate', '犹豫,踌躇;含糊,支吾 (v.)', 'v.', '/''hezɪteɪt/', '{"meaning":"犹豫,踌躇;含糊,支吾 (v.)","examples":["I hesitate. — 我犹豫。","don''t hesitate — 别再犹豫了","hesitate in — 吞吞吐吐"],"etymology":null}', 485),
