(3, 'inject', 'inject', '注射(药液等)；注入 (v.)', 'v.', '/ɪn''dʒekt/', '{"meaning":"注射(药液等)；注入 (v.)","examples":["His son was injected with strong drugs. — 他的儿子被注射了强效的药。"],"etymology":null}', 487),
(3, 'object', 'object', '物体;客体,对象;目标;宾语 (n.)；(to)反对 (v.)', 'n.', '/''ɒbdʒɪkt; -dʒekt/', '{"meaning":"物体;客体,对象;目标;宾语 (n.)；(to)反对 (v.)","examples":["an everyday object such as a spoon — 调羹之类的日常用品","a small metal object — 一个小金属物件","scientists studying plants, animals, or inanimate objects — 研究植物、动物或无生命物体的科学家"],"etymology":null}', 488),
(3, 'objection', 'objection', '(to)反对,异议,不喜欢,反对的理由 (n.)', 'n.', '/əb''dʒekʃ(ə)n/', '{"meaning":"(to)反对,异议,不喜欢,反对的理由 (n.)","examples":["Her objection was that he was too young. — 她反对的理由是他太小。"],"etymology":null}', 489),
(3, 'objective', 'objective', '目标,目的 (n.)；客观的,真实的 (adj.)', 'n.', '/əb''dʒektɪv/', '{"meaning":"目标,目的 (n.)；客观的,真实的 (adj.)","examples":["He vowed to achieve certain objectives before the end of his presidency. — 他立誓要在他的总统任期结束之前实现某些目标。","the best way to accomplish your objectives — 完成目标的最佳方法","The degree program has two main objectives. — 该学位课程有两个主要目标。"],"etymology":null}', 490),
(3, 'project', 'project', '方案,工程,项目v.投射,放映;设计,规划 (n.)', 'n.', '/prəˈdʒekt; ˈprɒdʒekt/', '{"meaning":"方案,工程,项目v.投射,放映;设计,规划 (n.)","examples":["The project aims to provide an analysis of children’s emotions. — 该计划旨在对儿童情绪作出分析。","a three-year research project — 一项为期三年的研究计划","The scheme will now be extended after a successful pilot project (= a small trial to test if an idea will be successful ) . — 试行成功后，该方案现在将得到推广。"],"etymology":null}', 491),
(3, 'projector', 'projector', '放映机,幻灯机,投影仪 (n.)', 'n.', '/prə''dʒektə/', '{"meaning":"放映机,幻灯机,投影仪 (n.)","examples":["...a slide projector. — …幻灯机。","overhead projector — n. 高射投影仪","slide projector — 幻灯机，幻灯片放映机"],"etymology":null}', 492),
(3, 'reject', 'reject', '拒绝,抵制,丢弃,排斥,退掉 (v.)；落选者 (n.)', 'v.', '/rɪ''dʒekt/', '{"meaning":"拒绝,抵制,丢弃,排斥,退掉 (v.)；落选者 (n.)","examples":["Sarah rejected her brother’s offer of help. — 萨拉拒绝了她弟弟的帮助。","Dexter flatly rejected (= completely rejected ) calls for his resignation. — 德克斯特断然拒绝让他辞职的要求。","His proposal was rejected outright (= completely rejected ) . — 他的建议被彻底否决了。"],"etymology":null}', 493),
(3, 'subject', 'subject', '主题;学科 (n.)；隶属的;易遭..的 (adj.)；使隶属 (v.)', 'n.', '/ˈsʌbdʒɪkt/', '{"meaning":"主题;学科 (n.)；隶属的;易遭..的 (adj.)；使隶属 (v.)","examples":["Paul has strong opinions on most subjects. — 保罗在大多数问题上观点激烈。","The subjects covered in this chapter are exercise and nutrition. — 本章涵盖的主题是运动和营养。","on the subject of — 涉及…时"],"etymology":null}', 494),
(3, 'subjective', 'subjective', '主观(上)的，个人的 (adj.)', 'adj.', '/səb''dʒektɪv/', '{"meaning":"主观(上)的，个人的 (adj.)","examples":["As a critic, he is far too subjective. — 作为评论家，他过于主观。","a highly subjective point of view — 相当主观的看法","subjective initiative — 主观能动性"],"etymology":null}', 495),
(3, 'collect', 'collect', '收集,搜集;领取,接走;收(税等);聚集,堆积 (v.)', 'v.', '/kə''lekt/', '{"meaning":"收集,搜集;领取,接走;收(税等);聚集,堆积 (v.)","examples":["After 25 years of collecting recipes, she has compiled them into a cookbook. — 她搜集了25年食谱，把它们编成一本烹饪书。","The company collects information about consumer trends. — 这家公司搜集有关消费者趋向的信息。","We’ve been out collecting signatures for our petition. — 我们出去为我们的请愿征集签名。"],"etymology":null}', 496),
(3, 'collection', 'collection', '收藏(品),收集(物) (n.)', 'n.', '/kə''lekʃ(ə)n/', '{"meaning":"收藏(品),收集(物) (n.)","examples":["a debt collection agency — 收债服务机构","a collection of — 一批，一些；收藏的；许多的；集…为一体的","data collection — 数据收集；资料收集"],"etymology":null}', 497),
(3, 'collective', 'collective', '集体 (n.)；集体的,共同的 (adj.)', 'n.', '/kə''lektɪv/', '{"meaning":"集体 (n.)；集体的,共同的 (adj.)","examples":["He will see that he is participating in all the decisions of the collective. — 他要确保他在参与集体企业的所有决策。","collective economy — 集体经济","collective action — 集体行动；集体行为"],"etymology":null}', 498),
(3, 'dialect', 'dialect', '方言 (n.)', 'n.', '/''daɪəlekt/', '{"meaning":"方言 (n.)","examples":["the local dialect — 当地方言","chinese dialect — 中国方言","local dialect — 地区方言"],"etymology":null}', 499),
(3, 'elect', 'elect', '选举,推选;选择,作出选择 (v.)', 'v.', '/ɪ''lekt/', '{"meaning":"选举,推选;选择,作出选择 (v.)","examples":["the country’s first democratically elected government — 该国第一个民主选举产生的政府","a new method for electing the leader of the party — 选举党领导的新方式","president elect — 当选总统（尚未就职的）"],"etymology":null}', 500);
