(3, 'select', 'select', '选择,挑选 (v.)；精选的,选择的 (adj.)', 'v.', '/sɪ''lekt/', '{"meaning":"选择,挑选 (v.)；精选的,选择的 (adj.)","examples":["a group of students selected at random — 随机挑选出来的一组学生","select all — 全部选择","select committee — 特别委员会（为某一特案组成的）"],"etymology":null}', 508),
(3, 'selection', 'selection', '选择,挑选;选集,精选物 (n.)', 'n.', '/sɪ''lekʃ(ə)n/', '{"meaning":"选择,挑选;选集,精选物 (n.)","examples":["The judges have made their final selection. — 评委已经作出最后的评选。","natural selection — 自然选择；[生]物竞天择说","type selection — 典型选择"],"etymology":null}', 509),
(3, 'lever', 'lever', '杆,杠杆,手段,途径,工具 (n.)', 'n.', '/''liːvə/', '{"meaning":"杆,杠杆,手段,途径,工具 (n.)","examples":["Pull this lever to open the gate. — 拉此横杆开启大门。","release lever — 解锁手柄；分离杆","lever principle — 杠杆原理"],"etymology":null}', 510),
(3, 'alleviate', 'alleviate', '减轻，缓和，缓解(痛苦等) (v.)', 'v.', '/ə''liːvɪeɪt/', '{"meaning":"减轻，缓和，缓解(痛苦等) (v.)","examples":["measures to alleviate poverty — 扶贫措施"],"etymology":null}', 511),
(3, 'elevate', 'elevate', '举起,提拔,振奋,提升...的职位 (v.)', 'v.', '/''elɪveɪt/', '{"meaning":"举起,提拔,振奋,提升...的职位 (v.)","examples":["Language has elevated humans above the other animals. — 语言使人类高于其他动物。"],"etymology":null}', 512),
(3, 'elevator', 'elevator', '电梯,升降机 (n.)', 'n.', '/''elɪveɪtə/', '{"meaning":"电梯,升降机 (n.)","examples":["We’ll have to take the elevator. — 我们只好坐电梯了。","bucket elevator — 斗式提升机；斗式运输机","take the elevator — 乘电梯"],"etymology":null}', 513),
(3, 'level', 'level', '水平，水准，等级 (n.)；弄平，铺平 (v.)；水平的 (adj.)', 'n.', '/''lev(ə)l/', '{"meaning":"水平，水准，等级 (n.)；弄平，铺平 (v.)；水平的 (adj.)","examples":["Inflation fell to its lowest level in 30 years. — 通货膨胀降至30年来最低点。","level of — …的水平；…的等级","high level — 高层；高电平"],"etymology":null}', 514),
(3, 'levy', 'levy', '征收,征税,征兵 (n.)；征收,征集,征用 (v.)', 'n.', '/''levɪ/', '{"meaning":"征收,征税,征兵 (n.)；征收,征集,征用 (v.)","examples":["...an annual levy on all drivers. — …向所有司机征收的年税。","tax levy — 纳税；征收税款","levy on — 征税；扣押"],"etymology":null}', 515),
(3, 'light', 'light', '光；灯 (n.)；点燃；照亮 (v.)；轻(快)；淡；明亮 (adj.)', 'n.', '/laɪt/', '{"meaning":"光；灯 (n.)；点燃；照亮 (v.)；轻(快)；淡；明亮 (adj.)","examples":["We waited for the lights to change. — 我们等着红绿灯转换。","Eventually the lights turned green. — 绿灯终于亮了。","The driver had failed to stop at a red light. — 红灯亮时司机没有把车停下。"],"etymology":null}', 516),
(3, 'highlight', 'highlight', '使显著,使突出;强调 (v.)；最精彩的部分 (n.)', 'v.', '/''haɪlaɪt/', '{"meaning":"使显著,使突出;强调 (v.)；最精彩的部分 (n.)","examples":["Your résumé should highlight your skills and achievements. — 你的简历应该突出自己的技能和成绩。"],"etymology":null}', 517),
(3, 'daylight', 'daylight', '日光,白昼,黎明 (n.)', 'n.', '/''deɪlaɪt/', '{"meaning":"日光,白昼,黎明 (n.)","examples":["The park is open to the public during daylight hours . — 公园白天对公众开放。","If possible, it’s better to work in natural daylight. — 如果条件允许的话，最好在自然日光下工作。","in broad daylight — 在大白天；公开地"],"etymology":null}', 518),
(3, 'delight', 'delight', '快乐,高兴 (n.)；(使)高兴,(使)欣喜 (v.)', 'n.', '/dɪ''laɪt/', '{"meaning":"快乐,高兴 (n.)；(使)高兴,(使)欣喜 (v.)","examples":["Throughout the house, the views are a constant source of surprise and delight. — 整个房子，目之所及不停带来惊奇和欣喜。","delight in — 因…感到快乐","with delight — 欣然"],"etymology":null}', 519),
(3, 'enlighten', 'enlighten', '启发,启蒙,教导 (v.)', 'v.', '/ɪn''laɪt(ə)n; en-/', '{"meaning":"启发,启蒙,教导 (v.)","examples":["A few dedicated doctors have fought for years to enlighten the profession. — 少数富有献身精神的医生为启蒙这一行业而奋斗多年。"],"etymology":null}', 520),
(3, 'lightning', 'lightning', '闪电 (n.)；闪电般的,快速的 (adj.)', 'n.', '/''laɪtnɪŋ/', '{"meaning":"闪电 (n.)；闪电般的,快速的 (adj.)","examples":["Two farmworkers were struck by lightning (= hit by lightning ). — 两个农民遭闪电击中。","Lightning flashed overhead. — 头顶上电光闪闪。","lightning protection — 防雷法"],"etymology":null}', 521),
(3, 'illuminate', 'illuminate', '照亮，照明；用灯光装饰；说明，阐释 (v.)', 'v.', '/ɪ''l(j)uːmɪneɪt/', '{"meaning":"照亮，照明；用灯光装饰；说明，阐释 (v.)","examples":["A single candle illuminated his face. — 一支蜡烛照亮了他的脸。","At night the canals are beautifully illuminated. — 晚上运河灯火辉煌，美景毕现。"],"etymology":null}', 522),
(3, 'lure', 'lure', '吸引力,魅力,诱惑物 (n.)；引诱，吸引 (v.)', 'n.', '/l(j)ʊə/', '{"meaning":"吸引力,魅力,诱惑物 (n.)；引诱，吸引 (v.)","examples":["The excitement of hunting big game in Africa has been a lure to Europeans for 200 years. — 在非洲捕捉大型猎物所带来的刺激，200年来一直吸引着欧洲人。"],"etymology":null}', 523),
(3, 'illusion', 'illusion', '幻想，错误的观念；错觉，幻觉，假象 (n.)', 'n.', '/ɪ''l(j)uːʒ(ə)n/', '{"meaning":"幻想，错误的观念；错觉，幻觉，假象 (n.)","examples":["She was under no illusion that he loved her. — 她不再幻想他爱她了。","It is an illusion that the Arctic is dark in winter. — 认为北极冬天一片黑暗是错误的。","She had no illusions about her physical attractiveness. — 她对自己外表的吸引力不抱幻想。"],"etymology":null}', 524),
(3, 'illustrate', 'illustrate', '举例说明,阐明;图解,加插图 (v.)', 'v.', '/''ɪləstreɪt/', '{"meaning":"举例说明,阐明;图解,加插图 (v.)","examples":["Let me give an example to illustrate the point. — 让我举个例子来说明这一点。","She illustrated her discussion with diagrams. — 她用图表来说明她的论述。","illustrate with — 用…来说明；给…加（插图）"],"etymology":null}', 525),
