(3, 'luxury', 'luxury', '奢侈,华贵;奢侈品 (n.)；奢华的,豪华的 (adj.)', 'n.', '/''lʌkʃ(ə)rɪ/', '{"meaning":"奢侈,华贵;奢侈品 (n.)；奢华的,豪华的 (adj.)","examples":["He was leading a life of luxury in Australia. — 他在澳大利亚过着豪华舒适的生活。","The dress is lambswool – pure luxury. — 礼服是用羔羊毛制作的——绝对奢华。","He could not afford luxury food on his pay. — 凭他的薪水，他吃不起奢侈的食品。"],"etymology":null}', 527),
(3, 'local', 'local', '地方的,当地的;局部的 (adj.)', 'adj.', '/''ləʊk(ə)l/', '{"meaning":"地方的,当地的;局部的 (adj.)","examples":["local hospital — 当地医院","local residents — 本地居民","local government — 地方政府；[总称]地方政府官员（或工作人员）"],"etymology":null}', 528),
(3, 'allocate', 'allocate', '分配，分派；拨给；划归 (v.)', 'v.', '/''æləkeɪt/', '{"meaning":"分配，分派；拨给；划归 (v.)","examples":["Tickets are limited and will be allocated to those who apply first. — 票数有限，将分配给那些先申请的人。","allocate funds — 拨款；分配资金","allocate for — 为…而分配；把…拨给"],"etymology":null}', 529),
