(3, 'synthetic', 'synthetic', '合成的,人造的;综合的 (adj.)', 'adj.', '/sɪn''θetɪk/', '{"meaning":"合成的,人造的;综合的 (adj.)","examples":["synthetic chemicals — 合成化学品","synthetic method — 综合法；合成法","synthetic aperture — 合成孔径"],"etymology":null}', 983),
