(3, 'second', 'second', '第二;次等的,二等的 (adj.)；秒 (n.)；赞成,附和 (v.)', 'adj.', '/''sek(ə)nd/', '{"meaning":"第二;次等的,二等的 (adj.)；秒 (n.)；赞成,附和 (v.)","examples":["the Second World War — 第二次世界大战","the second of August — 8月2日","a second year student — 二年级学生"],"etymology":null}', 990),
(3, 'consecutive', 'consecutive', '连续的；连贯的；顺序的 (adj.)', 'adj.', '/kən''sekjʊtɪv/', '{"meaning":"连续的；连贯的；顺序的 (adj.)","examples":["It had rained for four consecutive days. — 雨接连下了四天。","Can they win the title for the third consecutive season? — 他们能连续第三个赛季赢得冠军称号吗？","consecutive days — 连续营业日；连续作业日"],"etymology":null}', 991),
(3, 'persecute', 'persecute', '迫害 (v.)', 'v.', '/''pɜːsɪkjuːt/', '{"meaning":"迫害 (v.)","examples":["The Puritans left England to escape being persecuted. — 清教徒离开了英国以躲避迫害。"],"etymology":null}', 992),
