(3, 'foolish', 'foolish', '愚蠢的；傻的 (adj.)', 'adj.', '/''fuːlɪʃ/', '{"meaning":"愚蠢的；傻的 (adj.)","examples":["I’ve never heard anything so foolish in all my life. — 我这辈子从没听到过这么愚蠢的话。","It would be foolish to ignore his advice. — 不听他的劝告才傻呢。"],"etymology":null}', 4003),
(3, 'delegate', 'delegate', '委派…为代表 (v.)；代表 (n.)', 'v.', '/ˈdɛlɪˌɡeɪt; -ɡɪt; (for v.,) ˈdɛlɪˌɡeɪt/', '{"meaning":"委派…为代表 (v.)；代表 (n.)","examples":["Officials have now been delegated to start work on a draft settlement. — 官员们现已被委派开始准备一份拟定协议。","chief delegate — 首席代表"],"etymology":null}', 4004),
(3, 'irrigate', 'irrigate', '灌溉；冲洗；使清新 (v.)', 'v.', '/''ɪrɪgeɪt/', '{"meaning":"灌溉；冲洗；使清新 (v.)","examples":["The water in Lake Powell is used to irrigate the area. — 包尔湖的水被用来灌溉该地区。"],"etymology":null}', 4005),
(3, 'blanket', 'blanket', '毛毯，毯子；毯状物，覆盖层 (n.)；总括的，全体的；没有限制的 (adj.)；覆盖，掩盖；用毯覆盖 (v.)', 'n.', '/''blæŋkɪt/', '{"meaning":"毛毯，毯子；毯状物，覆盖层 (n.)；总括的，全体的；没有限制的 (adj.)；覆盖，掩盖；用毯覆盖 (v.)","examples":["The mud disappeared under a blanket of snow. — 泥地在一层白雪的覆盖下消失不见了。","There''s already a blanket ban on foreign unskilled labour in Japan. — 日本已经有一项禁止使用外国非熟练工人的通用禁令。","rubber blanket — 橡胶垫；橡皮布"],"etymology":null}', 4006),
(3, 'district', 'district', '区域；地方；行政区 (n.)', 'n.', '/''dɪstrɪkt/', '{"meaning":"区域；地方；行政区 (n.)","examples":["a postal district — 邮政区","business district — 商务区","urban district — 市区"],"etymology":null}', 4007),
(3, 'assassinate', 'assassinate', '暗杀；行刺 (v.)', 'v.', '/ə''sæsɪneɪt/', '{"meaning":"暗杀；行刺 (v.)","examples":["a plot to assassinate the President — 刺杀总统的阴谋"],"etymology":null}', 4008),
(3, 'mutter', 'mutter', '咕哝；喃喃自语 (v.)；咕哝；喃喃低语 (n.)', 'v.', '/''mʌtə/', '{"meaning":"咕哝；喃喃自语 (v.)；咕哝；喃喃低语 (n.)","examples":["Elsie muttered something I couldn’t catch and walked off. — 埃尔茜咕哝了一句什么，我也没有听懂，她就走掉了。","‘He’s such an unpleasant man,’ Alyssia muttered under her breath . — “他真是个讨厌的人。”阿莉西娅轻声嘟囔着。"],"etymology":null}', 4009),
(3, 'fortnight', 'fortnight', '两星期 (n.)', 'n.', '/''fɔːtnaɪt/', '{"meaning":"两星期 (n.)","examples":["a fortnight’s holiday — 十四天的假期","in a fortnight’s time — 两周后","a fortnight ago — 两周前"],"etymology":null}', 4010),
